/**
 * Pipeline — the coordinator. Mirrors `pipelinedPrefill()` from
 * `open-source/aether/src/gcp-coordinator.ts` but for CF Worker `Station`s.
 *
 * The Wallington Rotation:
 *   - Inner rotation: causal masking processes B tokens in one forward pass.
 *   - Outer rotation: log-rolling pipelines ceil(P/B) chunks across N stations.
 *   - Total steps:    ceil(P/B) + (N-1)
 *
 * The dispatch loop mirrors the aether coordinator verbatim:
 *   - `inFlight: (Promise<Result> | null)[]` indexed by station slot
 *   - `Promise.race(activePromises)` settles the next completion
 *   - On NaN poison we stop dispatching new work and drain in-flight ahead
 *
 * Single-station case: chunkSize = P, exactly ceil(P/B) = 1 call per chunk,
 * no inter-station hops. Generation falls back to per-token chunkSize=1.
 */

// Pipeline dispatch trace: set PIPELINE_TRACE=1 to log every dispatch/completion.
// Uses process.stderr.write when available (Node/Bun); no-op on CF Workers.
const TRACE = typeof process !== 'undefined' && process.env?.['PIPELINE_TRACE'] === '1';

// ─────────────────────────────────────────────────────────────────────────
// Amplituhedron coordinator (Death #2 — static volume cache)
// ─────────────────────────────────────────────────────────────────────────
//
// Wire layer for the host side of `AMPLITUHEDRON_PLAN.md` §4. The station
// endpoints `/amplituhedron/replay` and `/amplituhedron/capture` are live in
// `apps/distributed-inference-worker/src/index.ts:1880-1970`; this module
// fans them out across all stations from the host. Default ON; disable with
// `GNOSIS_AMPLITUHEDRON_COORDINATOR=0`.
//
// Per-station call surface is duck-typed (optional structural methods on
// IStation) so existing implementations (Station/StationUds/StationFlow/etc.)
// continue to satisfy the contract without an interface change. A station
// that does NOT implement these methods is treated as a permanent miss —
// the coordinator falls back to pipelinedPrefill as if the cache were empty.

/** Default ON. `GNOSIS_AMPLITUHEDRON_COORDINATOR=0|false` disables. */
function amplituhedronCoordinatorEnabled(): boolean {
  if (typeof process === 'undefined') return true;
  const v = process.env?.['GNOSIS_AMPLITUHEDRON_COORDINATOR'];
  if (v === undefined) return true;
  return !(v === '0' || v.toLowerCase() === 'false');
}

/**
 * Prompt-lookup / n-gram speculative decoding. DEFAULT OFF — when unset the
 * decode path is byte-identical to today. Enable with `MESH_SPEC_DECODE=1`
 * (env) or the per-Pipeline `specDecode` config override (query param → config).
 */
function meshSpecDecodeEnabledFromEnv(): boolean {
  if (typeof process === 'undefined') return false;
  const v = process.env?.['MESH_SPEC_DECODE'];
  if (v === undefined) return false;
  return v === '1' || v.toLowerCase() === 'true';
}

/** Draft length K for n-gram spec-decode. `MESH_SPEC_DECODE_K` env, default 4. */
function meshSpecDecodeKFromEnv(): number {
  if (typeof process === 'undefined') return 4;
  const v = process.env?.['MESH_SPEC_DECODE_K'];
  if (v === undefined) return 4;
  const n = Number.parseInt(v, 10);
  return Number.isInteger(n) && n >= 1 && n <= 8 ? n : 4;
}

/** Default for the spec-decode adaptive cost-gate knobs (see below). */
const SPEC_DECODE_DEFAULT_MIN_MATCH = 3;
const SPEC_DECODE_DEFAULT_COST_RATIO = 3.2;

/**
 * Minimum recurring-suffix match length before we DRAFT (a cost gate on draft
 * eligibility). `MESH_SPEC_DECODE_MIN_MATCH` env, default 3. A shorter n-gram
 * match (e.g. a single repeated token) is a weak signal: it draws a K-token
 * `/verify-batch` (~3.2× a single-token step here) that the model usually
 * rejects (accepted=0), so the round emits ONE token for K-token cost — a net
 * loss. Requiring a longer prior match means only high-continuation-probability
 * (high-acceptance) repeats draft; everything else takes the cheap 1-token step.
 * Min 1 (any match), no upper bound (clamped to the matcher's nMax in practice).
 */
function meshSpecDecodeMinMatchFromEnv(): number {
  if (typeof process === 'undefined') return SPEC_DECODE_DEFAULT_MIN_MATCH;
  const v = process.env?.['MESH_SPEC_DECODE_MIN_MATCH'];
  if (v === undefined) return SPEC_DECODE_DEFAULT_MIN_MATCH;
  const n = Number.parseInt(v, 10);
  return Number.isInteger(n) && n >= 1 ? n : SPEC_DECODE_DEFAULT_MIN_MATCH;
}

/**
 * The measured verify-cost ratio R = tK / t1 (K-candidate verify cost over a
 * single-token step). `MESH_SPEC_DECODE_COST_RATIO` env, default 3.2 (live L4
 * mistral-7b: tK≈242ms for K=4, t1≈76ms → R≈3.2). A drafted round emits
 * (accepted+1) tokens for cost tK; a 1-token round emits 1 for cost t1. Drafting
 * wins iff tK/(E[a]+1) < t1, i.e. E[a] > R - 1 (the break-even acceptance). The
 * adaptive gate suppresses drafting whenever the EWMA acceptance falls below
 * R-1. Clamped to >= 1.0 (R<1 would mean a batched verify is cheaper than a
 * single token, which is impossible — drafting would then always win).
 */
function meshSpecDecodeCostRatioFromEnv(): number {
  if (typeof process === 'undefined') return SPEC_DECODE_DEFAULT_COST_RATIO;
  const v = process.env?.['MESH_SPEC_DECODE_COST_RATIO'];
  if (v === undefined) return SPEC_DECODE_DEFAULT_COST_RATIO;
  const n = Number.parseFloat(v);
  return Number.isFinite(n) && n >= 1 ? n : SPEC_DECODE_DEFAULT_COST_RATIO;
}

/**
 * Whether the self-calibrating adaptive cost-gate is ON (default 1/ON). When
 * OFF (`MESH_SPEC_DECODE_ADAPTIVE=0`) spec-decode reverts to the prior
 * "draft on any match at fixed K" behavior (only useful for A/B measurement).
 * The gate is purely a performance decision and NEVER changes which tokens are
 * emitted — candidates=[] always degrades to one exact greedy step — so this
 * knob cannot affect correctness, only throughput.
 */
function meshSpecDecodeAdaptiveFromEnv(): boolean {
  if (typeof process === 'undefined') return true;
  const v = process.env?.['MESH_SPEC_DECODE_ADAPTIVE'];
  if (v === undefined) return true;
  return !(v === '0' || v.toLowerCase() === 'false');
}

/**
 * Compute a stable u64 prefix hash for `tokens[0..N]` as a decimal string.
 *
 * The plan (§4) names `blake3` but the host has no blake3 dep available
 * (`@a0n/aeon` doesn't expose one; `crypto-hash` isn't depended on either).
 * SHA-256 → first 8 bytes → u64 satisfies the Lean ledger's §8 "exact
 * byte-equal token sequences" requirement: distinct token streams map to
 * distinct u64s with probability ≈ 1 - 2^-64. The wire encoding is a
 * decimal string because JSON BigInt is not round-trippable.
 *
 * Cross-platform: `crypto.subtle.digest` is available in Node 22, Bun, CF
 * Workers, and modern browsers; no import required.
 */
export async function prefixHashU64(tokens: Uint32Array, domain?: string): Promise<string> {
  // Always materialize the token bytes into a fresh ArrayBuffer-backed view:
  // WebCrypto rejects SharedArrayBuffer, and domain-separation needs a
  // contiguous buffer we own.
  const tokenBytes = new Uint8Array(tokens.byteLength);
  tokenBytes.set(new Uint8Array(tokens.buffer, tokens.byteOffset, tokens.byteLength));
  // MODEL DOMAIN SEPARATION: residuals/KV are weight-specific, so a prefix
  // residual captured under one model must never be replayed for another that
  // merely shares prefix tokens. The consolidated mesh swaps models on ONE
  // service, so a model-agnostic key cross-contaminates. Prepend `<domain>\0`
  // before the token bytes → distinct models map to distinct prefix hashes.
  // Absent domain = legacy token-only hash (byte-identical to before).
  // Freshly-allocated, ArrayBuffer-backed (never SharedArrayBuffer) so WebCrypto
  // `digest` accepts it as a BufferSource.
  let bytesIn: Uint8Array<ArrayBuffer>;
  if (domain) {
    const dom = new TextEncoder().encode(domain);
    bytesIn = new Uint8Array(dom.length + 1 + tokenBytes.length);
    bytesIn.set(dom, 0);
    bytesIn[dom.length] = 0x00;
    bytesIn.set(tokenBytes, dom.length + 1);
  } else {
    bytesIn = tokenBytes;
  }
  // Sovereign bitwise XXH64 fingerprint (8 bytes / 64-bit). Faster than SHA-256
  // (no `crypto.subtle` round-trip) and pure-JS, so it works identically on every
  // host (Node/Bun/CF Workers/browser) — no FNV divergence fallback needed. Returns
  // the u64 as a decimal string, wire-compatible with the prior SHA-256-low-64 key
  // (the value changes, so the amplituhedron cache cold-starts once after deploy;
  // capture + replay share this one function so they stay consistent). Unifies the
  // transformer fleet's prefix key with the SSM fleet's bitwise key.
  const hex = cacheFingerprint64HexSync(bytesIn);
  return BigInt(`0x${hex}`).toString();
}

/**
 * Optional structural surface stations may implement to participate in the
 * Amplituhedron volume cache. Stations that omit these are treated as
 * permanent misses and the coordinator silently falls back to prefill.
 */
interface AmplituhedronReplayResult {
  hit: boolean;
  /**
   * Tail residual at position `prefixLen - 1`, shape `[hiddenDim]`. Only the
   * EXIT station is required to populate this on a hit — mid-pipeline
   * stations may return `undefined` (their KV-cache reseed is the
   * load-bearing side effect; their hit/miss flag is what the coordinator
   * gates on).
   */
  tailResidual?: Float32Array;
  tailFingerprint?: string;
  /**
   * Optional full residual stream at this station's output boundary, shape
   * `[prefixLen * hiddenDim]`. When a contiguous replay prefix provides this,
   * the host can recompute only the first missed station and its suffix.
   */
  prefixResidual?: Float32Array;
  prefixFingerprint?: string;
}

interface AmplituhedronReplayDecision {
  hit: boolean;
  tailResidual?: Float32Array;
  partialStartNodeIdx?: number;
  partialResidual?: Float32Array;
  partialFingerprint?: string;
  xorCertificate: TopologicalXorCertificate;
}

/**
 * Returns whether issue Amplituhedron Replay Xor Certificate is true.
 */
export function issueAmplituhedronReplayXorCertificate(args: {
  prefixHash: string;
  prefixLen: number;
  stationHits: readonly boolean[];
  roundSuffix?: string;
}): TopologicalXorCertificate {
  const activeLaneIndices = args.stationHits.flatMap((hit, laneIndex) =>
    hit ? [] : [laneIndex],
  );
  const mask = packedGrassmannianLaneMaskFromActiveLanes(
    args.stationHits.length,
    activeLaneIndices,
  );
  return issueGrassmannianXorRoundCertificateFromMask({
    roundId: `${args.prefixHash}:${args.prefixLen}:${args.roundSuffix ?? 'replay'}`,
    chart: 'distributed-inference-amplituhedron',
    mask,
    theoremRefs: ['Gnosis.GodBracket.god_gap_certificate'],
  });
}

interface AmplituhedronCapableStation {
  amplituhedronReplay?(args: {
    prefixHash: string;
    prefixLen: number;
    layerLo: number;
    layerHi: number;
    requestId?: string;
  }): Promise<AmplituhedronReplayResult>;
  amplituhedronCapture?(args: {
    prefixHash: string;
    prefixLen: number;
    layerLo: number;
    layerHi: number;
    tailResidual?: Float32Array;
    requestId?: string;
  }): Promise<void>;
}

function asAmplituhedronCapable(s: unknown): AmplituhedronCapableStation {
  return s as AmplituhedronCapableStation;
}

/**
 * Schedule a fire-and-forget side effect. Uses `ctx.waitUntil` when a CF
 * Worker `ExecutionContext` is reachable on `globalThis.__pipelineCtx` (the
 * host shim sets this when bootstrapping inside a Worker request);
 * otherwise falls back to `Promise.allSettled` + a stderr log on failure.
 * The promise itself is never awaited by the coordinator — the capture path
 * MUST NOT block decode.
 */
function fireAndForget(promise: Promise<unknown>, label: string): void {
  const g = globalThis as unknown as {
    __pipelineCtx?: { waitUntil(p: Promise<unknown>): void };
  };
  const ctx = g.__pipelineCtx;
  if (ctx && typeof ctx.waitUntil === 'function') {
    ctx.waitUntil(
      promise.catch((err: unknown) => {
        traceLog(`AMPLITUHEDRON ${label} fire-and-forget failed: ${String(err)}`);
      }),
    );
    return;
  }
  void Promise.allSettled([promise]).then((results) => {
    const r = results[0]!;
    if (r.status === 'rejected') {
      traceLog(`AMPLITUHEDRON ${label} fire-and-forget failed: ${String(r.reason)}`);
    }
  });
}


function traceLog(msg: string): void {
  if (!TRACE) return;
  try { process.stderr.write(`[PIPE_TRACE] ${msg}\n`); } catch { /* CF Worker — no stderr */ }
}
function traceFirst4(arr: Float32Array, label: string): string {
  if (!TRACE) return '';
  const f = [arr[0], arr[1], arr[2], arr[3]].map(v => (v ?? 0).toFixed(6));
  return ` ${label}_first4=[${f.join(',')}]`;
}

/**
 * Sovereign-sieve observability. Emitted once per armed probe on `stderr` (Cloud
 * Run captures it) so a canary shows, without a rebuild, WHICH prompt-hidden path
 * ran (native single-call `/generate` vs the host-orchestrated `computePromptHidden`
 * fallback), the station count that selected it, and whether the semantic KEY came
 * back usable (null vs a finite length + first value). Gated on the same flag that
 * arms the sieve (`MOONSHINE_SOVEREIGN_SIEVE` = 1/true/on) so it is zero-cost off.
 * This is the instrument that turns "the lane is silently inert" into a one-line
 * diagnosis (path + stations + hidden-null).
 */
function logSievePromptHiddenPath(
  path: 'native' | 'fallback',
  stations: number,
  promptHidden: Float32Array | null,
): void {
  const raw = typeof process !== 'undefined' ? process.env?.['MOONSHINE_SOVEREIGN_SIEVE'] : undefined;
  if (raw === undefined) return;
  const s = raw.trim().toLowerCase();
  if (s !== '1' && s !== 'true' && s !== 'on') return;
  const hidden = promptHidden ? `len=${promptHidden.length} first=${(promptHidden[0] ?? 0).toFixed(6)}` : 'NULL';
  try {
    process.stderr.write(`[SIEVE] promptHidden path=${path} stations=${stations} hidden=${hidden}\n`);
  } catch { /* CF Worker — no stderr */ }
}

